import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const VendorRegister = () => {
  const navigate = useNavigate();
  const [vendorData, setVendorData] = useState({
    vendor_name: '',
  });

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setVendorData({ ...vendorData, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('http://localhost:8000/vendor/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(vendorData),
      });
      if (!response.ok) throw new Error('Vendor registration failed');
      setVendorData({ vendor_name: '' });
      navigate('/vendor/manage'); // Navigate to home or another page upon success
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <label>
        Vendor Name:
        <input
          type="text"
          name="vendor_name"
          value={vendorData.vendor_name}
          onChange={handleInputChange}
          required
        />
      </label>
      <button type="submit">Register Vendor</button>
    </form>
  );
};

export default VendorRegister;
